import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, FormDisplay, getFormDisplayData, appActions, alertAction, history } from '../../utils';
import { routeNamesInventory } from '../../routeNames';
import { INVButton } from '../../Includes';
import { invSupplierActions } from "../config";


const style = theme => ({
    root: {
    },
    formContainer : {
        padding : 20,
        [theme.breakpoints.up("md")] : {
            padding : "20px 100px",
        }
    }
})
class _INVNewSuppliers extends Component {
    constructor(props) {
        super(props);
        this.state={
            loading : false,
        }
        const {dispatch} = this.props;
        headerActions({
            [headerStrings.headerTitle] : "NEW SUPPLIER",
            [headerStrings.backButtonAction] : ()=>{}
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Suppliers", path : routeNamesInventory.suppliers},
            {name : "New Supplier", path : routeNamesInventory.newSupplier},
        ])(dispatch);
        this.formConfig = [
            {name : "name", label : "Company Name", placeholder : "Name"},
            {name : "address", label : "Address", placeholder : "Address"},
            {name : "email", label : "Email", placeholder : "Email"},
            {name : "phone", label : "Phone", placeholder : "Phone"},
        ]
    }
    createSupplier(){
        const {dispatch} = this.props;
        // this.setState({loading : true});
        const data = getFormDisplayData(this.formContext)(
            (message, type)=>{
                appActions.showSnackbar(
                    alertAction[type](message)
                )(dispatch);
            }
        )
        if(data){
            invSupplierActions.createSupplier(data, (done, result)=>{
                this.setState({laoding : false});
                if(done)
                    history.replace(routeNamesInventory.supplier_+result._id, result);
            })(dispatch);
        }else this.setState({loading : false})
    }
    render() {
        const {classes} = this.props;
        const {loading} = this.state;
        return (
            <div className={classNames("animated", "zoomIn", classes.root)}>
                <div className={classes.formContainer}>
                    <div className={classNames("animated", "slideInLeft")}>
                        <FormDisplay
                            formName="newSupplier"
                            header="New Supplier"
                            getContext={context=>this.formContext=context}
                            formConfig={this.formConfig}
                        />
                    </div>
                    <div style={{marginTop : 20}}>
                        <INVButton
                            onClick={this.createSupplier.bind(this)}
                            loading={loading}>
                                Create Supplier
                            </INVButton>
                    </div>
                </div>
            </div>
        );
    }
}


_INVNewSuppliers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const INVNewSuppliers = connect(mapStateToProps)(withStyles(style)(_INVNewSuppliers));
export {INVNewSuppliers as default}